mapper.select:
SELECT 关联编号 FROM TRANSPORT_CONTRACT_VEHICLE
WHERE 合同编号 = #{contractId} AND 车辆编号 = #{vehicleId}
LIMIT 1

SELECT tcv.关联编号 AS relationId, tcv.合同编号 AS contractId, tc.合同单号 AS contractNo, tc.承运方名称 AS carrierName, tcv.车辆编号 AS vehicleId, v.车牌号 AS plateNo, v.车辆类型 AS vehicleType, v.车辆状态 AS vehicleStatus, v.公司名称 AS companyName, v.核载吨位 AS loadCapacity, DATE_FORMAT(tcv.关联时间, '%Y-%m-%d %H:%i:%s') AS relationTime, tcv.关联人编码 AS relationUserId, tcv.备注 AS remark FROM TRANSPORT_CONTRACT_VEHICLE tcv LEFT JOIN TRANSPORT_CONTRACT tc ON tcv.合同编号 = tc.合同编号 AND tc.是否删除 = 0 LEFT JOIN VEHICLE v ON tcv.车辆编号 = v.车辆编号 WHERE tcv.车辆编号 IN
#{vehicleId}
ORDER BY tcv.关联时间 DESC
